interface Route {
  method: string;
  pattern: string;
  paramNames: string[];
  regex: RegExp;
  handler: (params: Record<string, string>) => unknown;
}

const routes: Route[] = [];

export function addRoute(
  method: string,
  pattern: string,
  handler: (params: Record<string, string>) => unknown
): void {
  const paramNames: string[] = [];
  const regexStr = pattern.replace(/:([a-zA-Z_]+)/g, (_, name: string) => {
    paramNames.push(name);
    return '([^/]+)';
  });
  routes.push({
    method: method.toUpperCase(),
    pattern,
    paramNames,
    regex: new RegExp(`^${regexStr}$`),
    handler,
  });
}

export function resolveRoute(
  method: string,
  path: string
): { params: Record<string, string>; handler: (params: Record<string, string>) => unknown } | null {
  const upper = method.toUpperCase();
  for (const route of routes) {
    if (route.method !== upper) continue;
    const match = route.regex.exec(path);
    if (!match) continue;
    const params: Record<string, string> = {};
    route.paramNames.forEach((name, i) => {
      params[name] = match[i + 1] ?? '';
    });
    return { params, handler: route.handler };
  }
  return null;
}

export function notFoundResponse(): { status: number; body: { message: string } } {
  return { status: 404, body: { message: 'Not Found' } };
}

export type DomainError =
  | { kind: 'validation'; field: string; message: string }
  | { kind: 'not_found'; resource: string; id: string }
  | { kind: 'unauthorized'; reason: string }
  | { kind: 'conflict'; resource: string; conflictingId: string };

export function errorToStatus(err: DomainError): number {
  switch (err.kind) {
    case 'validation': return 422;
    case 'not_found': return 404;
    case 'unauthorized': return 401;
    case 'conflict': return 409;
  }
}

export function errorToBody(err: DomainError): { code: string; message: string; details?: unknown } {
  switch (err.kind) {
    case 'validation':
      return { code: 'VALIDATION_ERROR', message: err.message, details: { field: err.field } };
    case 'not_found':
      return { code: 'NOT_FOUND', message: `${err.resource} with id ${err.id} not found` };
    case 'unauthorized':
      return { code: 'UNAUTHORIZED', message: err.reason };
    case 'conflict':
      return { code: 'CONFLICT', message: `${err.resource} ${err.conflictingId} already exists` };
  }
}

export function formatErrorForLog(err: unknown): string {
  if (err instanceof Error) {
    return `[${err.name}] ${err.message}`;
  }
  return String(err);
}

export function envString(key: string, defaultValue: string): string {
  return process.env[key] || defaultValue;
}

export function envRequired(key: string): string {
  const val = process.env[key];
  if (!val) throw new Error(`Required environment variable ${key} is not set`);
  return val;
}

export function envInt(key: string, defaultValue: number): number {
  const val = process.env[key];
  if (!val) return defaultValue;
  const parsed = parseInt(val, 10);
  return Number.isNaN(parsed) ? defaultValue : parsed;
}

export interface AppConfig {
  databaseUrl: string;
  port: number;
  logLevel: string;
  enableMetrics: boolean;
}

export function loadConfig(): AppConfig {
  const missing: string[] = [];
  const check = (key: string): string => {
    const val = process.env[key];
    if (!val) { missing.push(key); return ''; }
    return val;
  };

  const databaseUrl = check('DATABASE_URL');
  const port = envInt('PORT', 3000);
  const logLevel = envString('LOG_LEVEL', 'info');
  const enableMetrics = (process.env['ENABLE_METRICS'] ?? 'false') === 'true';

  if (missing.length > 0) {
    throw new Error(`Missing required environment variables: ${missing.join(', ')}`);
  }
  return { databaseUrl, port, logLevel, enableMetrics };
}
